234	  private getBoxTraffic = (
235	    boxed: any
236	  ): {
237	    grpcIn: TrafficRateGrpc;
238	    grpcOut: TrafficRateGrpc;
239	    grpcTotal: TrafficRateGrpc;
240	    httpIn: TrafficRateHttp;
241	    httpOut: TrafficRateHttp;
242	    httpTotal: TrafficRateHttp;
243	    isGrpcRequests: boolean;
244	    tcpIn: TrafficRateTcp;
245	    tcpOut: TrafficRateTcp;
246	    tcpTotal: TrafficRateTcp;
247	  } => {
248	    const clusterBox = this.props.data.summaryTarget as Node;
249	    const data = clusterBox.getData();
250	    const cluster = data[NodeAttr.cluster];
251	
252	    let inboundEdges: Edge[] | any;
253	    let outboundEdges: Edge[] | any;
254	    let totalEdges: Edge[] | any;
255	
256	    const controller = (clusterBox as Node).getController();
257	    const { nodes } = elems(controller);
258	    const outsideNodes = select(nodes, { prop: NodeAttr.cluster, op: '!=', val: cluster }) as Node[];
259	    // inbound edges are from a different cluster
260	    inboundEdges = edgesOut(outsideNodes, boxed);
261	    // outbound edges are to a different different cluster
262	    outboundEdges = edgesIn(outsideNodes, boxed);
263	    // total edges are inbound + edges from boxed workload|app|root nodes (i.e. not injected service nodes or box nodes)
264	    totalEdges = [...inboundEdges];
265	    totalEdges.push(...edgesOut(select(boxed, { prop: NodeAttr.workload, op: 'truthy' }) as Node[]));
266	
267	    return {
268	      grpcIn: getAccumulatedTrafficRateGrpc(inboundEdges),
269	      grpcOut: getAccumulatedTrafficRateGrpc(outboundEdges),
270	      grpcTotal: getAccumulatedTrafficRateGrpc(totalEdges),
271	      httpIn: getAccumulatedTrafficRateHttp(inboundEdges),
272	      httpOut: getAccumulatedTrafficRateHttp(outboundEdges),
273	      httpTotal: getAccumulatedTrafficRateHttp(totalEdges),
274	      isGrpcRequests: this.props.trafficRates.includes(TrafficRate.GRPC_REQUEST),
275	      tcpIn: getAccumulatedTrafficRateTcp(inboundEdges),
276	      tcpOut: getAccumulatedTrafficRateTcp(outboundEdges),
277	      tcpTotal: getAccumulatedTrafficRateTcp(totalEdges)
278	    };
279	  };
280	
281	  private countApps = (boxed: any): { numApps: number; numVersions: number } => {
282	    const appVersions: { [key: string]: Set<string> } = {};
283	
284	    select(boxed, { prop: NodeAttr.nodeType, val: NodeType.APP }).forEach((node: GraphElement) => {
285	      const data = node.getData();
286	      const app = data[NodeAttr.app];
287	
288	      if (appVersions[app] === undefined) {
289	        appVersions[app] = new Set();
290	      }
291	
292	      appVersions[app].add(data[NodeAttr.version]);
293	    });
294	
295	    return {
296	      numApps: Object.getOwnPropertyNames(appVersions).length,
297	      numVersions: Object.getOwnPropertyNames(appVersions).reduce((totalCount: number, version: string) => {
298	        return totalCount + appVersions[version].size;
299	      }, 0)
300	    };
301	  };
302	
303	  private renderCluster = (cluster: string, kialiInstances: KialiInstance[]): React.ReactNode => {
304	    return (
305	      <React.Fragment key={cluster}>
306	        <PFBadge badge={PFBadges.Cluster} size="sm" />
307	        {cluster}
308	        {this.renderKialiLinks(kialiInstances)}
309	      </React.Fragment>
310	    );
311	  };
312	
313	  private renderKialiLinks = (kialiInstances: KialiInstance[]): React.ReactNode => {
314	    const kialiIcon = getKialiTheme() === Theme.DARK ? kialiIconDark : kialiIconLight;
315	
316	    return kialiInstances.map(instance => {
317	      if (instance.url.length !== 0) {
318	        return (
319	          <div>
320	            <img alt="Kiali Icon" src={kialiIcon} className={kialiIconStyle} />
321	            <a href={instance.url} target="_blank" rel="noopener noreferrer">
322	              {instance.namespace} {' / '} {instance.serviceName}
323	            </a>
324	          </div>
325	        );
326	      } else {
327	        return (
328	          <div>
329	            <img alt="Kiali Icon" src={kialiIcon} className={kialiIconStyle} />
330	            {`${instance.namespace} / ${instance.serviceName}`}
331	          </div>
332	        );
333	      }
334	    });
335	  };
336	
337	  private renderTopologySummary = (
338	    numSvc: number,
339	    numWorkloads: number,
340	    numApps: number,
341	    numVersions: number,
342	    numEdges: number
343	  ): React.ReactNode => (
344	    <div style={{ marginTop: '1rem' }}>
345	      {getTitle('Current Graph')}
346	
347	      {numApps > 0 && (
348	        <div>
349	          <KialiIcon.Applications className={topologyStyle} />
350	          {numApps.toString()} {numApps === 1 ? 'app ' : 'apps '}
351	          {numVersions > 0 && `(${numVersions} versions)`}
352	        </div>
353	      )}
354	
355	      {numSvc > 0 && (
356	        <div>
357	          <KialiIcon.Services className={topologyStyle} />
358	          {numSvc.toString()} {numSvc === 1 ? 'service' : 'services'}
359	        </div>
360	      )}
361	
362	      {numWorkloads > 0 && (
363	        <div>
364	          <KialiIcon.Workloads className={topologyStyle} />
365	          {numWorkloads.toString()} {numWorkloads === 1 ? 'workload' : 'workloads'}
366	        </div>
367	      )}
368	
369	      {numEdges > 0 && (
370	        <div>
371	          <KialiIcon.Topology className={topologyStyle} />
372	          {numEdges.toString()} {numEdges === 1 ? 'edge' : 'edges'}
373	        </div>
374	      )}
375	    </div>
376	  );
377	}

